const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,  // 15 minutes
  max: 100,                    // 100 requests per window per IP
  standardHeaders: true,
  legacyHeaders: false,
});

app.use(limiter);
```

---

### 4. 🔴 No CORS Configuration — Unrestricted Cross-Origin Access
Without explicit CORS configuration, the default behavior depends on the client, but adding proper CORS prevents unauthorized cross-origin requests to your API.

**OWASP A01:2021 – Broken Access Control**

```js
// ✅ Fix: Restrict CORS to known origins
const cors = require('cors');

app.use(cors({
  origin: ['https://yourdomain.com'],
  methods: ['GET'],
  allowedHeaders: ['Content-Type', 'Authorization'],
}));
